      |                                           ^~
```

Can you attach an example that shows the issue?  (Must be openly licensed, completely self-contained and self-checking so can directly run what you provide. Ideally use test_regress format, see https://veripool.org/guide/latest/contributing.html?highlight=test_regress#reporting-bugs

```
package tree_cfg_pkg;

  // Upper bounds for static arrays
  parameter int unsigned MAX_L      = 10;    // max levels supported
  parameter int unsigned MAX_LEAVES = 72;    // max leaves supported

  // Per-leaf attachment information
  typedef struct packed {
    int unsigned depth;                 // 0..levels (level where leaf is attached)
    // For a full path-based topology, you could add per-level digits here.
  } leaf_info_t;

  // Topology descriptor
  typedef struct {
    int unsigned levels;                // number of routing levels
    int unsigned k [MAX_L];             // fanout at each level (k[i] >= 1)
    int unsigned leaves;                // number of exposed leaves
    leaf_info_t  leaf [MAX_LEAVES];     // attach depth per leaf (unused entries ignored)
  } tree_topo_t;

endpackage

module tree_down_unicast import tree_cfg_pkg::*; #(
  parameter type MSG_T = logic [63:0],
  parameter tree_topo_t TOPO = tree_topo_t'{
    levels: 3,
    k     : '{0: 3, 1: 3, 2: 4, default:0},
    leaves: 36,
    leaf  : '{default:'{depth:3}}
  },
  parameter int PIPE_STAGES = 10
) (
  input  logic clk,
  input  logic rst_n,

  // Root channel
  input  logic                       root_valid,
  output logic                       root_ready,
  input  MSG_T                       root_data,
  input  logic [$clog2((TOPO.leaves>1)?TOPO.leaves:2)-1:0] leaf_id,

  // Leaf side
  output logic [TOPO.leaves-1:0]     leaf_valid,
  input  logic  [TOPO.leaves-1:0]    leaf_ready,
  output MSG_T [TOPO.leaves-1:0]     leaf_data
);

  // -------- Static topology checks (elaboration-time) --------
  function automatic int unsigned prod(int unsigned upto);
    int unsigned p = 1;
    for (int i=0;i<upto;i++) p *= (TOPO.k[i] > 0 ? TOPO.k[i] : 1);
    return p;
  endfunction

  initial begin
    // Maximum leaves topology can expose
    int unsigned max_leaves = prod(TOPO.levels);
    if (TOPO.levels == 0) $error("tree_down_unicast: TOPO.levels must be >= 1");
    if (TOPO.leaves == 0) $error("tree_down_unicast: TOPO.leaves must be >= 1");
    if (TOPO.leaves > MAX_LEAVES)
      $error("tree_down_unicast: leaves exceeds MAX_LEAVES");
    if (TOPO.leaves > max_leaves)
      $error("tree_down_unicast: leaves=%0d exceed topology capacity=%0d",
             TOPO.leaves, max_leaves);
    // Check each leaf’s attach depth
    for (int i=0;i<TOPO.leaves;i++) begin
      if (TOPO.leaf[i].depth > TOPO.levels)
        $error("Leaf %0d depth=%0d exceeds levels=%0d",
               i, TOPO.leaf[i].depth, TOPO.levels);
    end
  end

  // -------- Pipeline between root and (selected) leaf --------
  logic p_v, p_r;
  MSG_T p_d;

endmodule

module tb_tree_down_unicast;

  import tree_cfg_pkg::*;

  // -------- Example topology: 3 levels, fanouts {3,3,4} => 36 leaves --------
  localparam tree_topo_t TOPO_EX = '{
    levels: 3,
    k     : '{0: 3, 1: 3, 2: 4, default:0},
    leaves: 36,
    leaf  : '{default:'{depth:3}}   // all leaves hang at the last level here
  };

  // Message type: sequence + payload
  typedef struct packed {
    logic [15:0] seq;
    logic [47:0] payload;
  } msg_t;

  localparam int PIPE_STAGES = 10;

  // DUT ports
  logic clk=0, rst_n=0;

  logic                 root_v, root_r;
  msg_t                 root_d;
  logic [$clog2(TOPO_EX.leaves)-1:0] leaf_id;

  logic [TOPO_EX.leaves-1:0]    leaf_v, leaf_r;
  msg_t [TOPO_EX.leaves-1:0]    leaf_data;

  always #5 clk = ~clk;
  initial begin
    repeat (5) @(posedge clk);
    rst_n = 1;
  end

  // DUT
  tree_down_unicast #(
    .MSG_T(msg_t),
    .TOPO (TOPO_EX),
    .PIPE_STAGES(PIPE_STAGES)
  ) dut (
    .clk, .rst_n,
    .root_valid(root_v),
    .root_ready(root_r),
    .root_data (root_d),
    .leaf_id   (leaf_id),
    .leaf_valid(leaf_v),
    .leaf_ready(leaf_r),
    .leaf_data (leaf_data)
  );

  // -------- Traffic generator & scoreboard --------

  // Expected queues per leaf (testbench code)
  msg_t exp_q    [TOPO_EX.leaves][$];
  int   sent_cnt [TOPO_EX.leaves];
  int   got_cnt  [TOPO_EX.leaves];

  // Root source: drive N messages with uniform random leaf_id
  localparam int N_MSG = 1000;

  initial begin
    int unsigned seq = 0;

    for (int i=0;i<TOPO_EX.leaves;i++) begin
      sent_cnt[i]=0; got_cnt[i]=0; exp_q[i].delete();
    end
    root_v  = 0;
    root_d  = '0;
    leaf_id = '0;

    wait(rst_n);

    // keep issuing until N_MSG accepted
    while (seq < N_MSG) begin
      // Randomize a destination and payload
      msg_t m;
      automatic int unsigned dst = $urandom_range(0, TOPO_EX.leaves-1);
      m.seq     = seq[15:0];
      m.payload = {$urandom, $urandom} ^ (dst << 8);

      // Offer the message
      root_v  <= 1'b1;
      root_d  <= m;
      leaf_id <= dst;

      // If accepted, record in scoreboard and advance
      @(posedge clk);
      if (root_v && root_r) begin
        exp_q[dst].push_back(m);
        sent_cnt[dst]++;
        seq++;
      end
    end

    // Stop offering new messages
    root_v <= 1'b0;
  end

  // Per-leaf random ready & checking
  initial begin
    bit done;
    msg_t expm;
    wait(rst_n);
    forever begin
      // Random ready
      for (int i=0;i<TOPO_EX.leaves;i++) begin
        leaf_r[i] <= $urandom_range(0,1);
      end

      // Consume data when handshaked and compare to expected
      @(posedge clk);
      for (int i=0;i<TOPO_EX.leaves;i++) begin
        if (leaf_v[i] && leaf_r[i]) begin
          if (exp_q[i].size()==0) begin
            $fatal(1, "Leaf %0d got unexpected message seq=%0d", i, leaf_data[i].seq);
          end
          expm = exp_q[i].pop_front();
          if (leaf_data[i] !== expm) begin
            $fatal(1, "Leaf %0d data mismatch: got {seq=%0d,pay=0x%0h}, exp {seq=%0d,pay=0x%0h}",
                   i, leaf_data[i].seq, leaf_data[i].payload, expm.seq, expm.payload);
          end
          got_cnt[i]++;
        end
      end

      // Finish when all expected queues are empty and root stopped
      done = (root_v==0);
      for (int i=0;i<TOPO_EX.leaves;i++) done &= (exp_q[i].size()==0);
      if (done) begin
        int total = 0;
        for (int i=0;i<TOPO_EX.leaves;i++) begin
          if (sent_cnt[i] != got_cnt[i]) begin
            $fatal(1, "Count mismatch leaf %0d: sent=%0d got=%0d",
                   i, sent_cnt[i], got_cnt[i]);
          end
          total += got_cnt[i];
        end
        $display("PASS: %0d messages delivered correctly (leaves=%0d, PIPE_STAGES=%0d).",
                 total, TOPO_EX.leaves, PIPE_STAGES);
        $finish;
      end
    end
  end

  // Timeout

  initial begin
    #(1_000_000);
    $fatal(1, "Timeout");
  end

endmodule
